const body = items[0].json.body || {};
const u = String(body.username || '').toLowerCase().trim();
const p = String(body.password || '').trim();

// BASE DE DATOS DE USUARIOS INTEGRADA
const usuarios = {
  'dev': { pass: 'dev123', role: 'dev' },
  'admin': { pass: 'admin123', role: 'admin' },
  'operador': { pass: 'op123', role: 'op' }
};

if (usuarios[u] && usuarios[u].pass === p) {
  return [{
    json: {
      status: 'success',
      user: {
        username: u,
        role: usuarios[u].role
      }
    }
  }];
}

return [{
  json: {
    status: 'error',
    message: 'Usuario o contraseña incorrectos'
  }
}];
